// Course 0 must be taken before courses 1 and 2
// Courses 1 and 2 must be taken before course 3
// What's a valid order to take all four courses?

#include <iostream>
#include <vector>
#include <stack>

using namespace std;

void dfs(int current, vector<vector<int>> &adj, vector<bool> &visited, stack<int> &result)
{
    visited[current] = true;

    for (int neighbor : adj[current])
    {
        if (!visited[neighbor])
        {
            dfs(neighbor, adj, visited, result);
        }
    }

    result.push(current); // push AFTER all neighbors are fully done — postorder timing
}

int main()
{
    int vertices = 4;
    vector<vector<int>> adj(vertices);

    adj[0] = {1, 2}; // 0 must come before 1 and 2
    adj[1] = {3};    // 1 must come before 3
    adj[2] = {3};    // 2 must come before 3

    vector<bool> visited(vertices, false);
    stack<int> result;

    for (int v = 0; v < vertices; v++)
    {
        if (!visited[v])
        {
            dfs(v, adj, visited, result);
        }
    }

    while (!result.empty())
    {
        cout << result.top() << " ";
        result.pop();
    }

    return 0;
}

