#include <iostream>
#include <vector>
#include <queue>

using namespace std;

bool canFinish(int numCourses, vector<vector<int>>& prerequisites)
{
    vector<vector<int>> adj(numCourses);
    vector<int> inDegree(numCourses, 0);

    for (auto &p : prerequisites)
    {
        adj[p[1]].push_back(p[0]);
        inDegree[p[0]]++;
    }

    queue<int> q;
    for (int i = 0; i < numCourses; i++)
        if (inDegree[i] == 0) q.push(i);

    int completed = 0;
    while (!q.empty())
    {
        int course = q.front(); q.pop();
        completed++;
        for (int next : adj[course])
        {
            inDegree[next]--;
            if (inDegree[next] == 0) q.push(next);
        }
    }

    return completed == numCourses;
}

int main()
{
    vector<vector<int>> prerequisites = {{1, 0}, {2, 0}, {3, 1}, {3, 2}};
    cout << boolalpha << canFinish(4, prerequisites);

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

bool hasCycle(int course, vector<vector<int>>& adj, vector<int>& state)
{
    state[course] = 1; // visiting — currently on the recursion path

    for (int next : adj[course])
    {
        if (state[next] == 1) return true; // back edge to an in-progress vertex — cycle
        if (state[next] == 0 && hasCycle(next, adj, state)) return true;
    }

    state[course] = 2; // visited — fully explored, safe
    return false;
}

bool canFinish(int numCourses, vector<vector<int>>& prerequisites)
{
    vector<vector<int>> adj(numCourses);
    for (auto &p : prerequisites) adj[p[1]].push_back(p[0]);

    vector<int> state(numCourses, 0);
    for (int course = 0; course < numCourses; course++)
        if (state[course] == 0 && hasCycle(course, adj, state)) return false;

    return true;
}

int main()
{
    vector<vector<int>> prerequisites = {{1, 0}, {2, 0}, {3, 1}, {3, 2}};
    cout << boolalpha << canFinish(4, prerequisites);

    return 0;
}

