#include <iostream>
#include <vector>

using namespace std;

bool isSafe(int node, vector<vector<int>>& graph, vector<bool>& onPath, vector<int>& memo)
{
    if (memo[node] != -1) return memo[node] == 1;
    if (onPath[node]) return false;

    onPath[node] = true;
    bool safe = true;
    for (int next : graph[node])
        if (!isSafe(next, graph, onPath, memo)) { safe = false; break; }
    onPath[node] = false;

    memo[node] = safe ? 1 : 0;
    return safe;
}

vector<int> eventualSafeNodes(vector<vector<int>>& graph)
{
    int n = graph.size();
    vector<int> result;

    for (int node = 0; node < n; node++)
    {
        vector<bool> onPath(n, false);
        vector<int> memo(n, -1);
        if (isSafe(node, graph, onPath, memo)) result.push_back(node);
    }
    return result;
}

int main()
{
    vector<vector<int>> graph = {{1, 2}, {2, 3}, {5}, {0}, {5}, {}, {}};
    vector<int> result = eventualSafeNodes(graph);
    for (int n : result) cout << n << " ";

    return 0;
}

