#include <iostream>
#include <vector>

using namespace std;

bool dfsTopo(int node, vector<vector<int>>& adj, vector<int>& state, vector<int>& order)
{
    state[node] = 1;
    for (int next : adj[node])
    {
        if (state[next] == 1) return false;
        if (state[next] == 0 && !dfsTopo(next, adj, state, order)) return false;
    }
    state[node] = 2;
    order.push_back(node);
    return true;
}

vector<int> topoSort(vector<vector<int>>& adj, int n)
{
    vector<int> state(n, 0), order;
    for (int i = 0; i < n; i++)
        if (state[i] == 0 && !dfsTopo(i, adj, state, order)) return {};
    return order; // pushed in postorder — caller must reverse this to get true topological order
}

vector<int> sortItems(int n, int m, vector<int>& group, vector<vector<int>>& beforeItems)
{
    int totalGroups = m;
    for (int i = 0; i < n; i++)
        if (group[i] == -1) group[i] = totalGroups++;

    vector<vector<int>> itemAdj(n), groupAdj(totalGroups);
    for (int i = 0; i < n; i++)
        for (int before : beforeItems[i])
        {
            itemAdj[before].push_back(i);
            if (group[before] != group[i]) groupAdj[group[before]].push_back(group[i]);
        }

    vector<int> itemOrderRev = topoSort(itemAdj, n);
    vector<int> groupOrderRev = topoSort(groupAdj, totalGroups);
    if (itemOrderRev.empty() && n > 0) return {};
    if (groupOrderRev.empty() && totalGroups > 0) return {};

    vector<int> itemOrder(itemOrderRev.rbegin(), itemOrderRev.rend());
    vector<int> groupOrder(groupOrderRev.rbegin(), groupOrderRev.rend());

    vector<vector<int>> buckets(totalGroups);
    for (int item : itemOrder) buckets[group[item]].push_back(item);

    vector<int> result;
    for (int g : groupOrder)
        for (int item : buckets[g]) result.push_back(item);

    return result;
}

int main()
{
    vector<int> group = {0, 0, 1, 1, -1};
    vector<vector<int>> beforeItems = {{}, {0}, {}, {2}, {}};

    vector<int> result = sortItems(5, 2, group, beforeItems);
    for (int r : result) cout << r << " ";

    return 0;
}

#include <iostream>
#include <vector>
#include <queue>

using namespace std;

vector<int> kahnTopoSort(vector<vector<int>>& adj, int n)
{
    vector<int> inDegree(n, 0);
    for (int u = 0; u < n; u++)
        for (int v : adj[u]) inDegree[v]++;

    queue<int> q;
    for (int i = 0; i < n; i++)
        if (inDegree[i] == 0) q.push(i);

    vector<int> order;
    while (!q.empty())
    {
        int u = q.front(); q.pop();
        order.push_back(u);
        for (int v : adj[u])
            if (--inDegree[v] == 0) q.push(v);
    }

    return (int)order.size() == n ? order : vector<int>();
}

vector<int> sortItems(int n, int m, vector<int>& group, vector<vector<int>>& beforeItems)
{
    int totalGroups = m;
    for (int i = 0; i < n; i++)
        if (group[i] == -1) group[i] = totalGroups++;

    vector<vector<int>> itemAdj(n), groupAdj(totalGroups);
    for (int i = 0; i < n; i++)
        for (int before : beforeItems[i])
        {
            itemAdj[before].push_back(i);
            if (group[before] != group[i]) groupAdj[group[before]].push_back(group[i]);
        }

    vector<int> itemOrder = kahnTopoSort(itemAdj, n);
    vector<int> groupOrder = kahnTopoSort(groupAdj, totalGroups);
    if ((int)itemOrder.size() != n || (int)groupOrder.size() != totalGroups) return {};

    vector<vector<int>> buckets(totalGroups);
    for (int item : itemOrder) buckets[group[item]].push_back(item);

    vector<int> result;
    for (int g : groupOrder)
        for (int item : buckets[g]) result.push_back(item);

    return result;
}

int main()
{
    vector<int> group = {0, 0, 1, 1, -1};
    vector<vector<int>> beforeItems = {{}, {0}, {}, {2}, {}};

    vector<int> result = sortItems(5, 2, group, beforeItems);
    for (int r : result) cout << r << " ";

    return 0;
}

